effect.shader:
void main() {
    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    float rad = angle * 0.0174533;
    vec2 velocity = vec2(cos(rad)*strength,-sin(rad)*strength);
    //velocity *= acPreviewSize/getTexSize(inputImg.size);
    velocity.x *= acScreenSize.y / acScreenSize.x;
    float speed = length(velocity / texelSize);
    int nSamples = int(clamp(speed, 1.01, 100.01));
    vec4 originalColor = texture2DCv(inputImg.texture,acScreenNorm.st);
    vec4 outColor = originalColor;
    outColor.rgb = outColor.a > 0.0 ? outColor.rgb/outColor.a : outColor.rgb;
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = velocity * (float(i) / float(nSamples - 1) - (0.5+bias/2.0));
        vec2 sampleCoord = acScreenNorm.st-offset;
        float insideTexture = step(0.0,sampleCoord.x) * step(sampleCoord.x,1.0) * step(0.0,sampleCoord.y) * step(sampleCoord.y,1.0);
        vec4 c = texture2DCv(inputImg.texture, sampleCoord) * insideTexture;
        float r;
        float g;
        float b;
        float a;
        if( rmode == 0 ) {
            r = min(outColor.r,c.r);
        } else if( rmode == 1 ) {
            r = max(outColor.r,c.r);
        } else if( rmode == 3 ) {
            r = outColor.r + c.r;
        } else {
            r = outColor.r;
        }
        if( gmode == 0 ) {
            g = min(outColor.g,c.g);
        } else if( gmode == 1 ) {
            g = max(outColor.g,c.g);
        } else if( gmode == 3 ) {
            g = outColor.g + c.g;
        } else {
            g = outColor.g;
        }
        if( bmode == 0 ) {
            b = min(outColor.b,c.b);
        } else if( bmode == 1 ) {
            b = max(outColor.b,c.b);
        } else if( bmode == 3 ) {
            b = outColor.b + c.b;
        } else {
            b = outColor.b;
        }
        if( amode == 0 ) {
            a = min(outColor.a,c.a);
        } else if( amode == 1 ) {
            a = max(outColor.a,c.a);
        } else if( amode == 3 ) {
            a = outColor.a + c.a;
        } else {
            a = outColor.a;
        }
        outColor = vec4(r,g,b,a);
    }
    outColor = outColor / vec4(
        rmode == 3 ? float(nSamples) : 1.0,
        gmode == 3 ? float(nSamples) : 1.0,
        bmode == 3 ? float(nSamples) : 1.0,
        amode == 3 ? float(nSamples) : 1.0
    );
    outColor.rgb *= outColor.a;
    gl_FragColor = mix(originalColor,outColor,alpha);
}
